SELECT BOARD_ID as "boardId", BOARD_TYPE as "boardType", TITLE as "title", CRET_USER_ID as "cretUserId", to_char(CRET_DT, 'YYYY-MM-DD HH24:MI') as "cretDt", to_char(UPDT_DT, 'YYYY-MM-DD HH24:MI') as "updtDt", VIEW_CNT as "viewCnt" FROM TB_BOARD WHERE 1=1
AND BOARD_TYPE = #{boardType}
AND (TITLE LIKE '%' || #{keyword} || '%' OR CONTENT LIKE '%' || #{keyword} || '%')
ORDER BY CRET_DT DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM TB_BOARD WHERE 1=1
AND BOARD_TYPE = #{boardType}
AND (TITLE LIKE '%' || #{keyword} || '%' OR CONTENT LIKE '%' || #{keyword} || '%')
